import React, { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import './AdminDashboard.css';

const AdminDashboard = () => {
  const [campaigns, setCampaigns] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [deletingId, setDeletingId] = useState(null);
  const [deleteError, setDeleteError] = useState('');
  const [deleteSuccess, setDeleteSuccess] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState({ total: 0, totalRaised: 0, totalGoal: 0 });

  const fetchAllCampaigns = useCallback(async () => {
    try {
      setLoading(true);
      setError('');
      const { data } = await axios.get('/api/campaigns/admin/all');
      setCampaigns(data.campaigns);

      // Compute stats
      const totalRaised = data.campaigns.reduce((acc, c) => acc + c.raised, 0);
      const totalGoal = data.campaigns.reduce((acc, c) => acc + c.goal, 0);
      setStats({ total: data.campaigns.length, totalRaised, totalGoal });
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to load campaigns.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAllCampaigns();
  }, [fetchAllCampaigns]);

  const handleDelete = async (campaignId, campaignTitle) => {
    if (!window.confirm(`Are you sure you want to permanently delete "${campaignTitle}"? This action cannot be undone.`)) {
      return;
    }

    try {
      setDeletingId(campaignId);
      setDeleteError('');
      setDeleteSuccess('');

      await axios.delete(`/api/campaigns/${campaignId}`);

      setCampaigns((prev) => prev.filter((c) => c._id !== campaignId));
      setStats((prev) => ({
        ...prev,
        total: prev.total - 1
      }));
      setDeleteSuccess(`Campaign "${campaignTitle}" was deleted successfully.`);

      setTimeout(() => setDeleteSuccess(''), 4000);
    } catch (err) {
      setDeleteError(err.response?.data?.message || 'Failed to delete campaign.');
      setTimeout(() => setDeleteError(''), 4000);
    } finally {
      setDeletingId(null);
    }
  };

  const filteredCampaigns = campaigns.filter((c) =>
    c.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.category.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (c.creator?.name || '').toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="admin-page">
      <div className="container">
        {/* Header */}
        <div className="admin-header" id="admin-header">
          <div>
            <h1 className="page-title gradient-text">⚙️ Admin Dashboard</h1>
            <p style={{ color: 'var(--text-muted)', marginTop: '0.4rem' }}>
              Manage all campaigns on the FundIt platform.
            </p>
          </div>
          <Link to="/create-campaign" className="btn btn-primary btn-sm" id="admin-create-btn">
            + New Campaign
          </Link>
        </div>

        {/* Stats Cards */}
        <div className="admin-stats" id="admin-stats">
          <div className="stat-card" id="stat-total-campaigns">
            <div className="stat-icon">📋</div>
            <div className="stat-value">{stats.total}</div>
            <div className="stat-label">Total Campaigns</div>
          </div>
          <div className="stat-card" id="stat-total-raised">
            <div className="stat-icon">💰</div>
            <div className="stat-value gradient-text">₹{stats.totalRaised.toLocaleString('en-IN')}</div>
            <div className="stat-label">Total Raised</div>
          </div>
          <div className="stat-card" id="stat-total-goal">
            <div className="stat-icon">🎯</div>
            <div className="stat-value">₹{stats.totalGoal.toLocaleString('en-IN')}</div>
            <div className="stat-label">Combined Goal</div>
          </div>
          <div className="stat-card" id="stat-success-rate">
            <div className="stat-icon">📈</div>
            <div className="stat-value">
              {stats.totalGoal > 0
                ? Math.round((stats.totalRaised / stats.totalGoal) * 100)
                : 0}%
            </div>
            <div className="stat-label">Overall Progress</div>
          </div>
        </div>

        {/* Alerts */}
        {deleteSuccess && (
          <div className="alert alert-success" id="admin-delete-success" role="alert">
            <span>✅</span>
            <p>{deleteSuccess}</p>
          </div>
        )}
        {deleteError && (
          <div className="alert alert-error" id="admin-delete-error" role="alert">
            <span>⚠️</span>
            <p>{deleteError}</p>
          </div>
        )}

        {/* Search */}
        <div className="admin-search-wrapper" id="admin-search-wrapper">
          <input
            type="text"
            id="admin-search"
            className="form-input"
            placeholder="🔍 Search by title, category, or creator..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            style={{ borderRadius: 'var(--radius-full)', maxWidth: '400px' }}
          />
          <span style={{ color: 'var(--text-muted)', fontSize: '0.875rem' }}>
            {filteredCampaigns.length} of {campaigns.length} campaigns
          </span>
        </div>

        {/* Table */}
        <div className="admin-table-wrapper card" id="admin-table-wrapper">
          {loading ? (
            <div className="loading-state">
              <div className="spinner spinner-lg"></div>
              <p>Loading campaigns...</p>
            </div>
          ) : error ? (
            <div className="alert alert-error" id="admin-load-error">
              <span>⚠️</span>
              <p>{error}</p>
            </div>
          ) : filteredCampaigns.length === 0 ? (
            <div className="empty-state" id="admin-empty">
              <div className="empty-icon">📋</div>
              <h3>{searchTerm ? 'No matching campaigns' : 'No campaigns yet'}</h3>
              <p>{searchTerm ? 'Try a different search term.' : 'Create the first campaign to get started.'}</p>
            </div>
          ) : (
            <div className="table-scroll">
              <table className="data-table" id="campaigns-admin-table">
                <thead>
                  <tr>
                    <th>#</th>
                    <th>Campaign Title</th>
                    <th>Category</th>
                    <th>Creator</th>
                    <th>Goal (₹)</th>
                    <th>Raised (₹)</th>
                    <th>Progress</th>
                    <th>Status</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredCampaigns.map((campaign, index) => {
                    const progress = Math.min(Math.round((campaign.raised / campaign.goal) * 100), 100);
                    const isGoalReached = campaign.raised >= campaign.goal;

                    return (
                      <tr key={campaign._id} id={`admin-row-${campaign._id}`}>
                        <td style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>
                          {index + 1}
                        </td>
                        <td>
                          <Link
                            to={`/campaigns/${campaign._id}`}
                            id={`admin-campaign-link-${campaign._id}`}
                            style={{
                              color: 'var(--text-primary)',
                              fontWeight: 600,
                              fontSize: '0.9rem',
                              maxWidth: '200px',
                              display: 'block',
                              overflow: 'hidden',
                              textOverflow: 'ellipsis',
                              whiteSpace: 'nowrap'
                            }}
                            title={campaign.title}
                          >
                            {campaign.title}
                          </Link>
                        </td>
                        <td>
                          <span className="badge badge-primary">{campaign.category}</span>
                        </td>
                        <td style={{ fontSize: '0.875rem', color: 'var(--text-secondary)' }}>
                          {campaign.creator?.name || 'N/A'}
                        </td>
                        <td style={{ fontWeight: 600 }}>
                          {campaign.goal.toLocaleString('en-IN')}
                        </td>
                        <td style={{ fontWeight: 600, color: 'var(--success)' }}>
                          {campaign.raised.toLocaleString('en-IN')}
                        </td>
                        <td style={{ minWidth: '120px' }}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                            <div style={{ flex: 1 }}>
                              <div className="progress-bar-wrapper" style={{ height: '6px' }}>
                                <div
                                  className="progress-bar-fill"
                                  style={{ width: `${progress}%` }}
                                ></div>
                              </div>
                            </div>
                            <span style={{ fontSize: '0.78rem', color: 'var(--text-muted)', minWidth: '35px' }}>
                              {progress}%
                            </span>
                          </div>
                        </td>
                        <td>
                          {isGoalReached ? (
                            <span className="badge badge-success">✓ Funded</span>
                          ) : campaign.isActive ? (
                            <span className="badge badge-primary">Active</span>
                          ) : (
                            <span className="badge" style={{ background: 'rgba(107,107,133,0.15)', color: 'var(--text-muted)', border: '1px solid var(--border)' }}>
                              Inactive
                            </span>
                          )}
                        </td>
                        <td>
                          <div style={{ display: 'flex', gap: '0.5rem' }}>
                            <Link
                              to={`/campaigns/${campaign._id}`}
                              className="btn btn-secondary btn-sm"
                              id={`btn-view-${campaign._id}`}
                              style={{ fontSize: '0.78rem', padding: '0.4rem 0.75rem' }}
                            >
                              View
                            </Link>
                            <button
                              className="btn btn-danger btn-sm"
                              id={`btn-delete-${campaign._id}`}
                              onClick={() => handleDelete(campaign._id, campaign.title)}
                              disabled={deletingId === campaign._id}
                              style={{ fontSize: '0.78rem', padding: '0.4rem 0.75rem' }}
                            >
                              {deletingId === campaign._id ? (
                                <span className="spinner" style={{ width: '14px', height: '14px' }}></span>
                              ) : (
                                'Delete'
                              )}
                            </button>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
